external_knowledge:
- 'well-oiled Spark applications' refers to active Spark configurations (is_active = 1); 
- 'plenty of practice' refers to having more than 10 associated runtime metrics (COUNT(rm.metric_id) > 10); 
- 'ran smoothly throughout January 2023' means the creation date of the configuration application falls within the date range '2023-01-01 00:00:00' AND '2023-01-31 23:59:59'.

sql:
SELECT version_name
FROM spark_versions
WHERE end_of_life > CURRENT_DATE;

SELECT version_name
FROM spark_versions
WHERE version_id = 0;

SELECT COUNT(*) AS active_config_count
FROM spark_configurations
WHERE is_active = 1;

SELECT config_id, version_id, is_active
FROM spark_configurations
WHERE is_active = 1;

SELECT AVG(runtime) AS average_runtime
FROM runtime_metrics
WHERE config_id = 0;
